variables.graphqlSchema:
type Query {
  hero(episode: Episode): Character
  reviews(episode: Episode!): [Review]
}

type Mutation {
  createReview(episode: Episode!, review: ReviewInput!): Review
}

enum Episode {
  NEWHOPE
  EMPIRE
  JEDI
}

type Character {
  id: ID!
  name: String!
  appearsIn: [Episode]!
}

type Review {
  episode: Episode
  stars: Int!
  commentary: String
}

input ReviewInput {
  stars: Int!
  commentary: String
}
